function ComponentShowcase() {
  const { div, h2, p, pre, code: codeEl } = tags;
  const name = 'Button';
  const description = 'Interactive button component with multiple variants and sizes.';
  const variants = [
    Button({ variant: 'primary' }, 'Primary'),
    Button({ variant: 'secondary' }, 'Secondary'),
    Button({ variant: 'outline' }, 'Outline'),
    Button({ variant: 'ghost' }, 'Ghost')
  ];
  const code = "Button({ variant: 'primary' }, 'Click me')";

  return Card({ class: css('_flex _col _gap4') },
    Card.Header({},
      div({ class: css('_flex _aic _gap3') },
        h2({ class: css('_heading4') }, name),
        Badge({}, 'Component')
      ),
      p({ class: css('_fgmuted _textsm _mt1') }, description)
    ),
    Card.Body({},
      Tabs({ items: [
        { label: 'Preview', content: () =>
          div({ class: css('_flex _wrap _gap4 _p4 _bgmuted _r4') }, ...variants)
        },
        { label: 'Code', content: () =>
          pre({ class: css('_p4 _bgmuted _r4 _overflow[auto]') }, codeEl({}, code))
        }
      ] })
    )
  );
}
